<template>
    <div class="tarozi_list_container">
        <!-- Header Section -->
        <div class="tarozi_list_header main_header_bg_new">
            <div class="header_content">
                <div class="header_title">
                    <h5 class="mb-2">
                        <mdb-icon icon="list-alt" class="mr-2"/>
                        {{$t('tarozi_list') || 'Список тарози'}}
                    </h5>
                </div>
                <div class="header_actions">
                    <div class="search_wrapper">
                        <mdb-input 
                            class="search_input m-0" 
                            v-model="search" 
                            :placeholder="$t('search') || 'Поиск...'" 
                            size="sm"  
                            outline  
                            group 
                            type="text"
                        >
                            <mdb-icon icon="search" class="search_icon"/>
                        </mdb-input>
                    </div>
                    <router-link to="/add_tarozi">
                        <mdb-btn 
                            class="add_btn m-0 mb-2 px-3" 
                            color="success"
                            size="sm"
                        >
                            <mdb-icon icon="plus" class="mr-1"/>
                            {{$t('add')}}
                        </mdb-btn>
                    </router-link>
                </div>
            </div>
        </div>

        <!-- Table Section -->
        <div class="tarozi_list_table_wrapper">
            <loader v-if="loading"/>
            <div v-else class="table_container">
                <table class="tarozi_table">
                    <thead>
                        <tr class="table_header">
                            <th width="50" class="text-center">№</th>
                            <th>{{$t('ticket_number')}}</th>
                            <th>{{$t('shafyor_name')}}</th>
                            <th>{{$t('car_number')}}</th>
                            <th>{{$t('phone_number')}}</th>
                            <th>{{$t('product')}}</th>
                            <th>Общий масса</th>
                            <th>{{$t('note')}}</th>
                            <th>{{$t('date')}}</th>
                        </tr>
                    </thead>
                    <tbody>
                        <tr 
                            v-for="(row, index) in filteredList" 
                            :key="index" 
                            @click="enter_invoice_new(row.id)"
                            class="table_row"
                        >
                            <td class="text-center">
                                <span class="row_number">{{index+1}}</span>
                            </td>
                            <td>
                                <span class="ticket_badge" v-if="row.ticket && row.ticket.ticket_number">
                                    {{row.ticket.ticket_number}}
                                </span>
                                <span class="text-muted" v-else>-</span>
                            </td>
                            <td>
                                <div class="shafyor_info">
                                    <i v-if="row.TegirmonClientNewid" class="fas fa-star text-warning mr-1"></i>
                                    <span class="shafyor_name">{{row.shafyor_name}}</span>
                                    <span v-if="row.TegirmonClientNewid && row.client" class="client_name">
                                        ({{row.client.fio}})
                                    </span>
                                </div>
                            </td>
                            <td>
                                <span class="car_number">{{row.car_number || '-'}}</span>
                            </td>
                            <td>
                                <span class="phone_number">{{row.shafyor_tel || '-'}}</span>
                            </td>
                            <td>
                                <span class="product_name">{{row.text_1 || '-'}}</span>
                            </td>
                            <td>
                                <span class="measure_badge">{{formatNumber(row.all_measure)}} кг</span>
                            </td>
                            <td>
                                <span class="note_text" :title="row.note">{{row.note || '-'}}</span>
                            </td>
                            <td>
                                <div class="date_info d-flex">
                                    <span class="date_text mr-1">
                                        {{formatDate(row.date_first_pull)}}
                                    </span>
                                    <span class="time_text ml-1">
                                        {{formatTime(row.date_first_pull)}}
                                    </span>
                                </div>
                            </td>
                        </tr>
                        <tr v-if="filteredList.length === 0" class="empty_row">
                            <td colspan="9" class="text-center py-4">
                                <mdb-icon icon="inbox" class="mb-2" style="font-size: 48px; color: #ccc;"/>
                                <p class="text-muted mb-0">{{$t('no_data') || 'Данные не найдены'}}</p>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>
        </div>
    </div>
</template>

<script>
import {mdbInput, mdbBtn, mdbIcon} from 'mdbvue'
import { mapGetters, mapActions } from 'vuex';
export default {
    components: {
        mdbInput, mdbBtn, mdbIcon,
    },
    data() {
        return {
            search: '',
            loading: false,
        }
    },
    async mounted () {
      await this.fetchTarozi_list();
    },
    computed: {
      ...mapGetters(['get_tarozi_tortilgan_list']),
      filteredList() {
        if (!this.search || this.search.trim() === '') {
          return this.get_tarozi_tortilgan_list || [];
        }
        const searchLower = this.search.toLowerCase();
        return (this.get_tarozi_tortilgan_list || []).filter(row => {
          const shafyorName = (row.shafyor_name || '').toLowerCase();
          const carNumber = (row.car_number || '').toLowerCase();
          const phone = (row.shafyor_tel || '').toLowerCase();
          const product = (row.text_1 || '').toLowerCase();
          const note = (row.note || '').toLowerCase();
          const ticketNumber = (row.ticket && row.ticket.ticket_number) ? row.ticket.ticket_number.toLowerCase() : '';
          const clientFio = (row.client && row.client.fio) ? row.client.fio.toLowerCase() : '';
          
          return shafyorName.includes(searchLower) ||
                 carNumber.includes(searchLower) ||
                 phone.includes(searchLower) ||
                 product.includes(searchLower) ||
                 note.includes(searchLower) ||
                 ticketNumber.includes(searchLower) ||
                 clientFio.includes(searchLower);
        });
      }
    },
    methods: {
      ...mapActions(['fetchTarozi_list']),
      async enter_invoice_new(invoice_id){
        this.$router.push('add_last_tarozi/' + invoice_id)
      },
      formatNumber(num) {
        if (!num) return '0';
        return parseFloat(num).toFixed(1).replace(/\B(?=(\d{3})+(?!\d))/g, ' ');
      },
      formatDate(dateString) {
        if (!dateString) return '-';
        return dateString.slice(8,10) + '-' + dateString.slice(5,7) + '-' + dateString.slice(0,4);
      },
      formatTime(dateString) {
        if (!dateString) return '';
        return dateString.slice(11,16);
      }
    },
}
</script>

<style lang="scss" scoped>
