    flex-wrap: wrap;
    gap: 16px;
  }

  .header_title {
    h5 {
      color: #ffffff;
      font-weight: 600;
      display: flex;
      // align-items: center;
    }
    small {
      font-size: 12px;
      // margin-top: 4px;
      display: block;
    }
  }

  .header_actions {
    display: flex;
    align-items: center;
    gap: 12px;
    flex-wrap: wrap;
  }

  .search_wrapper {
    position: relative;
    min-width: 250px;

    .search_input {
      margin: 0;
    }

    .search_icon {
      position: absolute;
      right: 12px;
      top: 50%;
      transform: translateY(-50%);
      color: #6c757d;
      pointer-events: none;
    }
  }

  .add_btn {
    font-size: 10px;
    padding: 6px 14px;
    border-radius: 2px;
    font-weight: 500;
    box-shadow: 0 2px 4px rgba(40, 167, 69, 0.2);
    transition: all 0.3s ease;

    &:hover {
      transform: translateY(-1px);
      box-shadow: 0 4px 8px rgba(40, 167, 69, 0.3);
