      padding: 60px 20px;
    }
  }
}

// Responsive design
@media (max-width: 768px) {
  .tarozi_list_header {
    .header_content {
      flex-direction: column;
      align-items: stretch;
    }

    .header_actions {
      flex-direction: column;
      width: 100%;

      .search_wrapper {
        width: 100%;
        min-width: auto;
      }

      .add_btn {
        width: 100%;
      }
    }
  }

  .tarozi_table {
    font-size: 11px;

